import { Component, OnInit, isDevMode } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Invoice } from '../../models/invoice';
import { InvoiceCalcService, InvoiceTotals } from '../../services/invoice-calc.service';
import { InvoiceStoreService } from '../../services/invoice-store.service';
import { ElectronService } from '../../services/electron.service';

@Component({
  selector: 'app-invoice-preview',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './invoice-preview.component.html',
  styleUrls: ['./invoice-preview.component.css']
})
export class InvoicePreviewComponent implements OnInit {
  invoice: Invoice | null = null;

  totals: InvoiceTotals = {
    totalHT: 0,
    totalTVA: 0,
    totalTTC: 0,
    remise: 0,
    totalHTApresRemise: 0,
    totalTVAApresRemise: 0
  };

  logoAvailable = true;

  // debug (optionnel)
  readonly isDev = isDevMode();
  debugUrl = '';
  debugId = '';
  debugCount = 0;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private store: InvoiceStoreService,
    public calc: InvoiceCalcService,
    public electron: ElectronService
  ) {}

  async ngOnInit(): Promise<void> {
    // 1) charger les données
    await this.store.load();

    // 2) URL robuste (Angular + window)
    const urlFromAngular = this.router.url ?? '';
    const urlFromWindow =
      window.location.href ??
      window.location.hash ??
      window.location.pathname ??
      '';

    const rawUrl = (urlFromAngular || urlFromWindow || '').toString();
    this.debugUrl = rawUrl || '(empty)';

    // 3) récupérer l'id via Angular params
    let id =
      this.route.snapshot.paramMap.get('id') ??
      this.route.snapshot.paramMap.get('invoiceId') ??
      '';

    // 4) fallback: extraire l'id depuis l'URL (si paramMap vide)
    if (!id && this.debugUrl) {
      const patterns: RegExp[] = [
        /\/invoices\/([^\/]+)\/preview/i,
        /\/invoices\/preview\/([^\/]+)/i,
        /#\/invoices\/([^\/]+)\/preview/i
      ];

      for (const re of patterns) {
        const m = this.debugUrl.match(re);
        if (m?.[1]) {
          id = m[1];
          break;
        }
      }
    }

    this.debugId = id;
    this.debugCount = this.store.getSnapshot().length;

    if (this.isDev) {
      console.log('[InvoicePreview] debug', {
        urlFromAngular,
        urlFromWindow,
        debugUrl: this.debugUrl,
        id: this.debugId,
        count: this.debugCount
      });
    }

    if (!id) {
      this.invoice = null;
      return;
    }

    // 5) charger la facture depuis le store (source unique)
    const inv = await this.store.getById(id);
    this.invoice = inv;

    if (inv) {
      this.totals = this.calc.totals(inv);
    } else if (this.isDev) {
      console.warn('[InvoicePreview] invoice not found for id:', id);
    }
  }

  back(): void {
    this.router.navigate(['/invoices']);
  }

  edit(): void {
    if (!this.invoice) return;
    this.router.navigate(['/invoices', this.invoice.id, 'edit']);
  }

  print(): void {
    window.print();
  }

  async exportPdf(): Promise<void> {
    if (!this.invoice) return;
    if (!this.electron.isElectron) return;

    try {
      const anyElectron: any = this.electron as any;

      if (typeof anyElectron.exportPdf === 'function') {
        await anyElectron.exportPdf();
        return;
      }

      if (anyElectron.ipcRenderer?.invoke) {
        await anyElectron.ipcRenderer.invoke('export-pdf');
        return;
      }

      alert('Export PDF non configuré dans ElectronService.');
    } catch (e) {
      console.error(e);
      alert('Erreur export PDF. Voir console.');
    }
  }
}
<div *ngIf="isDev" style="padding:8px;font-size:12px;opacity:.7">
  DEBUG url={{ debugUrl }} | id={{ debugId }} | count={{ debugCount }}
</div>

<div class="preview-toolbar no-print">
  <button class="btn ghost" (click)="back()">Retour</button>
  <div class="toolbar-actions">
    <button class="btn outline" (click)="edit()" [disabled]="!invoice">Modifier</button>
    <button class="btn primary" (click)="print()" [disabled]="!invoice">Imprimer</button>
    <button class="btn ghost" *ngIf="electron.isElectron" (click)="exportPdf()" [disabled]="!invoice">
      Exporter PDF
    </button>
  </div>
</div>

<div class="invoice-page" *ngIf="invoice as inv">
  <header class="invoice-header">
    <div class="logo-wrap">
      <img
        *ngIf="logoAvailable"
        src="assets/logo.png"
        alt="SPA logo"
        (error)="logoAvailable = false"
      >
      <div *ngIf="!logoAvailable" class="logo-fallback">SPA</div>
    </div>
    <div class="company-info">
      <h1>SPA — Société d’Aluminium</h1>
      <p>Vente et fabrication aluminium</p>
      <p>Adresse : Zone Industrielle, Tunisie</p>
      <p>Tél : +216 00 000 000 | Email : contact@spa.tn | MF : 0000000/A/M/000</p>
    </div>
  </header>

  <section class="invoice-meta">
    <div class="client-block">
      <h2>Facturer à</h2>
      <p class="strong">{{ inv.client.nom }}</p>
      <p>{{ inv.client.adresse }}</p>
      <p>Tél : {{ inv.client.tel }}</p>
      <p *ngIf="inv.client.mf">MF : {{ inv.client.mf }}</p>
      <p *ngIf="inv.client.email">Email : {{ inv.client.email }}</p>
    </div>
    <div class="invoice-block">
      <div>
        <span>Numéro</span>
        <strong>{{ inv.numero }}</strong>
      </div>
      <div>
        <span>Date</span>
        <strong>{{ inv.date | date:'dd/MM/yyyy' }}</strong>
      </div>
      <div>
        <span>Conditions</span>
        <strong>{{ inv.conditions || 'Paiement à réception' }}</strong>
      </div>
    </div>
  </section>

  <table class="invoice-table">
    <thead>
      <tr>
        <th>Désignation</th>
        <th>Unité</th>
        <th>Qté</th>
        <th>PU</th>
        <th>HT</th>
        <th>TVA</th>
        <th>TTC</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let line of inv.lignes">
        <td>{{ line.designation }}</td>
        <td>{{ line.unite }}</td>
        <td class="num">{{ line.quantite | number:'1.2-2' }}</td>
        <td class="num">{{ line.prixUnitaire | number:'1.2-2' }}</td>
        <td class="num">{{ calc.lineHT(line) | number:'1.2-2' }}</td>
        <td class="num">{{ calc.lineTVA(line) | number:'1.2-2' }} ({{ line.tvaRate }}%)</td>
        <td class="num">{{ calc.lineTTC(line) | number:'1.2-2' }}</td>
      </tr>
    </tbody>
  </table>

  <section class="invoice-totals">
    <div class="totals-box">
      <div>
        <span>Total HT</span>
        <strong>{{ totals.totalHT | number:'1.2-2' }} DT</strong>
      </div>
      <div>
        <span>Total TVA</span>
        <strong>{{ totals.totalTVA | number:'1.2-2' }} DT</strong>
      </div>
      <div *ngIf="totals.remise > 0">
        <span>Remise</span>
        <strong>- {{ totals.remise | number:'1.2-2' }} DT</strong>
      </div>
      <div class="grand-total">
        <span>Total TTC</span>
        <strong>{{ totals.totalTTC | number:'1.2-2' }} DT</strong>
      </div>
    </div>
  </section>

  <section class="invoice-notes" *ngIf="inv.notes">
    <h3>Notes</h3>
    <p>{{ inv.notes }}</p>
  </section>

  <footer class="invoice-footer">
    Merci pour votre confiance — SPA
  </footer>
</div>

<div class="empty card" *ngIf="!invoice">
  Facture introuvable.
</div>
